from collections import defaultdict

def longest_unique_path(nums, edges):
    graph = defaultdict(list)
    for u, v in edges:
        graph[u].append(v)
        graph[v].append(u)

    max_length = 0
    min_nodes = float('inf')

    def dfs(node, parent, path, count):
        nonlocal max_length, min_nodes
        if len(count) > max_length:
            max_length = len(count)
            min_nodes = len(path)
        elif len(count) == max_length:
            min_nodes = min(min_nodes, len(path))

        for neighbor in graph[node]:
            if neighbor != parent:
                new_count = count.copy()
                new_count[nums[neighbor]] = new_count.get(nums[neighbor], 0) + 1
                if new_count[nums[neighbor]] <= 2:
                    dfs(neighbor, node, path + [neighbor], new_count)

    for i in range(len(nums)):
        count = {nums[i]: 1}
        dfs(i, -1, [i], count)

    if max_length == 0:
        return [0, 0]
    else:
        return [sum(nums) - max_length + 1, min_nodes]

