from collections import defaultdict

def longest_special_path(nums, edges):
    n = len(nums)
    graph = defaultdict(list)
    for u, v in edges:
        graph[u].append(v)
        graph[v].append(u)

    def dfs(node, parent, path):
        count = defaultdict(int)
        for num in path:
            count[num] += 1
        if count[nums[node]] > 2:
            return 0, float('inf')
        count[nums[node]] += 1
        max_len = 0
        min_nodes = float('inf')
        for child in graph[node]:
            if child != parent:
                child_len, child_nodes = dfs(child, node, path + [nums[node]])
                if child_len > max_len:
                    max_len = child_len
                    min_nodes = child_nodes
                elif child_len == max_len:
                    min_nodes = min(min_nodes, child_nodes)
        if max_len == 0:
            return 1, 1
        return max_len + 1, min_nodes

    max_len = 0
    min_nodes = float('inf')
    for i in range(n):
        length, nodes = dfs(i, -1, [])
        if length > max_len:
            max_len = length
            min_nodes = nodes
        elif length == max_len:
            min_nodes = min(min_nodes, nodes)
    return [max_len, min_nodes] if max_len > 0 else [0, 0]

