def longest_special_path(nums, edges):
    n = len(nums)
    graph = defaultdict(list)
    for u, v in edges:
        graph[u].append(v)
        graph[v].append(u)

    max_length = 0
    min_nodes = float('inf')

    def dfs(node, parent, path, count):
        nonlocal max_length, min_nodes
        if len(count) > 2:
            return
        path.append(node)
        count[nums[node]] = count.get(nums[node], 0) + 1
        if len(count) == 2 and all(v <= 2 for v in count.values()):
            max_length = max(max_length, len(path))
            min_nodes = min(min_nodes, len(path))
